extension HybridWebViewController: WKScriptMessageHandler {
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard isOriginAllowed(message.frameInfo.request.url) else {
            print("Message from unauthorized origin rejected")
            return
        }
        
        guard let body = message.body as? [String: Any] else {
            sendErrorToWebView(handler: message.name, error: "Invalid message format")
            return
        }
        
        let completion: (Result<[String: Any], Error>) -> Void = { [weak self] result in
            guard let self = self else { return }
            switch result {
            case .success(let data):
                self.sendSuccessToWebView(handler: message.name, data: data)
            case .failure(let error):
                self.sendErrorToWebView(handler: message.name, error: error.localizedDescription)
            }
        }
        
        switch message.name {
        case "nativeCamera":
            handleCameraRequest(params: body, completion: completion)
        case "nativePushNotifications":
            handlePushNotificationRequest(params: body, completion: completion)
        case "nativeInAppPurchase":
            handleInAppPurchaseRequest(params: body, completion: completion)
        default:
            sendErrorToWebView(handler: message.name, error: "Unknown handler")
        }
    }
    
    private func sendSuccessToWebView(handler: String, data: [String: Any]) {
        guard let jsonData = try? JSONSerialization.data(withJSONObject: data),
              let jsonString = String(data: jsonData, encoding: .utf8) else {
            return
        }
        
        let escapedString = jsonString.replacingOccurrences(of: "\\", with: "\\\\")
            .replacingOccurrences(of: "'", with: "\\'")
            .replacingOccurrences(of: "\n", with: "\\n")
            .replacingOccurrences(of: "\r", with: "\\r")
        
        let script = "window.dispatchEvent(new CustomEvent('\(handler)Response', {detail: {success: true, data: \(escapedString)}}));"
        
        DispatchQueue.main.async {
            self.webView.evaluateJavaScript(script)
        }
    }
    
    private func sendErrorToWebView(handler: String, error: String) {
        let sanitizedError = error.replacingOccurrences(of: "'", with: "\\'")
            .replacingOccurrences(of: "\n", with: " ")
            .replacingOccurrences(of: "\r", with: " ")
        
        let script = "window.dispatchEvent(new CustomEvent('\(handler)Response', {detail: {success: false, error: '\(sanitizedError)'}}));"
        
        DispatchQueue.main.async {
            self.webView.evaluateJavaScript(script)
        }
    }
